async (params, browser) => {
  // Open Slack
  await browser.open('https://app.slack.com')

  // Let Slack load
  await browser.wait(3000)

  // Fetch channel history via Slack API
  const result = await browser.evaluate(`const localConfig = localStorage.getItem('localConfig_v2'); if (!localConfig) throw new Error('Not logged into Slack'); const config = JSON.parse(localConfig); const teamId = Object.keys(config.teams)[0]; const token = config.teams[teamId].token; const chanResp = await fetch('/api/conversations.list?types=public_channel,private_channel&limit=200', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/x-www-form-urlencoded' } }); const chanData = await chanResp.json(); const channel = chanData.channels?.find(c => c.name === params.channel_name); if (!channel) return { success: false, message: 'Channel not found: ' + params.channel_name + '' }; const limit = Math.min(parseInt(params.limit) || 20, 100); const resp = await fetch('/api/conversations.history', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/x-www-form-urlencoded' }, body: 'channel=' + channel.id + '&limit=' + limit }); const data = await resp.json(); if (!data.ok) throw new Error('History failed: ' + data.error); const messages = (data.messages || []).map(m => ({ text: m.text?.substring(0, 300) || '', user: m.user || '', ts: m.ts, type: m.subtype || 'message', reactions: (m.reactions || []).map(r => r.name + ':' + r.count).join(', ') })); return { channel: '' + params.channel_name + '', result_count: messages.length, messages: messages }`)

  return result
}
